mem_references_02.complete:
class Point { int x; }
public class Main {
    static void modifier(Point p, int val) {
        p.x += 10; // Référence modifiée
        val += 10; // Primitif inchangé
    }
    public static void main(String[] args) {
        Point pt = new Point();
        int v = 10;
        modifier(pt, v);
        System.out.println(pt.x + " " + v); // 10, 10
    }
}

